346	            switch (anchor.name) {
347	                .root => {
348	                    this.builder.append(.latin1, "root");
349	                },
350	                .array_item => {
351	                    this.builder.append(.latin1, "item");
352	                    this.builder.append(.usize, anchor.name.array_item);
353	                },
354	                .prop_value => |prop_value| {
355	                    if (prop_value.prop_name.length() == 0) {
356	                        this.builder.append(.latin1, "value");
357	                        this.builder.append(.usize, prop_value.counter);
358	                    } else {
359	                        this.builder.append(.string, anchor.name.prop_value.prop_name);
360	                        if (anchor.name.prop_value.counter != 0) {
361	                            this.builder.append(.usize, anchor.name.prop_value.counter);
362	                        }
363	                    }
364	                },
365	            }
366	
367	            if (anchor.anchored) {
368	                return;
369	            }
370	
371	            switch (this.space) {
372	                .minified => {
373	                    this.builder.append(.lchar, ' ');
374	                },
375	                .number, .str => {
376	                    this.newline();
377	                },
378	            }
379	            anchor.anchored = true;
380	        }
381	
382	        if (unwrapped.isArray()) {
383	            var iter = try unwrapped.arrayIterator(global);
384	
385	            if (iter.len == 0) {
