929	pub fn parse(
930	    global: *jsc.JSGlobalObject,
931	    callFrame: *jsc.CallFrame,
932	) bun.JSError!jsc.JSValue {
933	    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
934	    defer arena.deinit();
935	    const allocator = arena.allocator();
936	
937	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
938	    var ast_scope = ast_memory_allocator.enter(allocator);
939	    defer ast_scope.exit();
940	
941	    const input_value = callFrame.argumentsAsArray(1)[0];
942	
943	    const input: jsc.Node.BlobOrStringOrBuffer = try jsc.Node.BlobOrStringOrBuffer.fromJS(global, arena.allocator(), input_value) orelse input: {
944	        var str = try input_value.toBunString(global);
945	        defer str.deref();
946	        break :input .{ .string_or_buffer = .{ .string = str.toSlice(arena.allocator()) } };
947	    };
948	    defer input.deinit();
949	
950	    var log = logger.Log.init(bun.default_allocator);
951	    defer log.deinit();
952	
953	    const source = &logger.Source.initPathString("input.yaml", input.slice());
954	
955	    const root = bun.interchange.yaml.YAML.parse(source, &log, arena.allocator()) catch |err| return switch (err) {
956	        error.OutOfMemory => |oom| oom,
957	        error.StackOverflow => global.throwStackOverflow(),
958	        else => {
959	            if (log.msgs.items.len > 0) {
960	                const first_msg = log.msgs.items[0];
961	                const error_text = first_msg.data.text;
962	                return global.throwValue(global.createSyntaxErrorInstance("YAML Parse error: {s}", .{error_text}));
963	            }
964	            return global.throwValue(global.createSyntaxErrorInstance("YAML Parse error: Unable to parse YAML string", .{}));
965	        },
966	    };
967	
968	    var ctx: ParserCtx = .{
969	        .seen_objects = .init(arena.allocator()),
970	        .stack_check = .init(),
971	        .global = global,
972	        .root = root,
973	        .result = .zero,
974	    };
975	    defer ctx.deinit();
976	
977	    MarkedArgumentBuffer.run(ParserCtx, &ctx, &ParserCtx.run);
978	
979	    return ctx.result;
980	}
