4	    pub fn parse(source: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) ParseError!Expr {
5	        bun.analytics.Features.yaml_parse += 1;
6	
7	        var parser: Parser(.utf8) = .init(allocator, source.contents);
8	
9	        const stream = parser.parse() catch |e| {
10	            const err: Parser(.utf8).ParseResult = .fail(e, &parser);
11	            try err.err.addToLog(source, log);
12	            return error.SyntaxError;
13	        };
14	
15	        return switch (stream.docs.items.len) {
16	            0 => .init(E.Null, .{}, .Empty),
17	            1 => stream.docs.items[0].root,
18	            else => {
19	
20	                // multi-document yaml streams are converted into arrays
21	
22	                var items: bun.BabyList(Expr) = try .initCapacity(allocator, stream.docs.items.len);
23	
24	                for (stream.docs.items) |doc| {
25	                    items.appendAssumeCapacity(doc.root);
26	                }
27	
28	                return .init(E.Array, .{ .items = items }, .Empty);
29	            },
30	        };
31	    }
32	};
