  test("parses empty string", () => {
    expect(INI.parse("")).toEqual({});
  });

  test("parses global key=value", () => {
    expect(INI.parse("key=value")).toEqual({ key: "value" });
  });

  test("parses key: value (colon separator)", () => {
    expect(INI.parse("key: value")).toEqual({ key: "value" });
  });

  test("parses sections as nested objects", () => {
    expect(INI.parse("[section]\nkey=value")).toEqual({ section: { key: "value" } });
  });

  test("skips semicolon comments", () => {
    expect(INI.parse("; comment\nkey=value")).toEqual({ key: "value" });
  });

  test("skips hash comments", () => {
    expect(INI.parse("# comment\nkey=value")).toEqual({ key: "value" });
  });

  test("strips inline comments from values", () => {
    expect(INI.parse("key=value ; comment")).toEqual({ key: "value" });
