/// Self-contained INI parser.
///
/// Produces an `Expr` AST with:
/// - global key=value pairs at the top level
/// - `[section]` headers as nested objects
///
/// Supported syntax:
/// - Blank lines (ignored)
/// - Comment lines starting with `;` or `#` (ignored)
/// - Section headers: `[section_name]`
/// - Key-value pairs: `key=value` or `key: value`
/// - Keys and values are whitespace-trimmed
/// - Windows `\r\n` line endings are handled
pub const INI = struct {
    pub fn parse(source_: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) !Expr {
        _ = log;

        const contents = source_.contents;
        if (contents.len == 0) {
            return Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
        }

        const root_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
        const root_obj = root_expr.data.e_object;
        // `current_obj` tracks which section we are currently populating.
        // It starts as the root object (global/no-section keys).
        var current_obj: *E.Object = root_obj;

        var pos: usize = 0;
        while (pos < contents.len) {
            // Find the end of the current line.
            const line_start = pos;
            while (pos < contents.len and contents[pos] != '\n') : (pos += 1) {}
            const line_end = pos;
            if (pos < contents.len) pos += 1; // advance past the '\n'

            var raw_line = contents[line_start..line_end];

            // Strip trailing '\r' for Windows line endings.
            if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r') {
                raw_line = raw_line[0 .. raw_line.len - 1];
            }

            const line = strings.trimSpaces(raw_line);
            if (line.len == 0) continue; // blank line

            // Comment lines.
            if (line[0] == ';' or line[0] == '#') continue;

            if (line[0] == '[') {
                // Section header: [section_name]
                const maybe_close = strings.indexOfChar(line, ']');
                if (maybe_close == null) continue; // malformed, skip
                const close_idx: usize = @intCast(maybe_close.?);

                const section_name = strings.trimSpaces(line[1..close_idx]);
                if (section_name.len == 0) continue;

                // If the section already exists in root, reuse its object so
                // that duplicate section headers merge rather than overwrite.
                if (root_obj.get(section_name)) |existing| {
                    if (existing.data == .e_object) {
                        current_obj = existing.data.e_object;
                        continue;
                    }
                }

                // Create a new nested object for this section.
                const section_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
                try root_obj.put(allocator, section_name, section_expr);
                current_obj = section_expr.data.e_object;
            } else {
                // Key-value pair: prefer '=' as separator, fall back to ':'.
                var sep_idx: ?usize = null;
                if (strings.indexOfChar(line, '=')) |p| {
                    sep_idx = @intCast(p);
                } else if (strings.indexOfChar(line, ':')) |p| {
                    sep_idx = @intCast(p);
                }
                const sep = sep_idx orelse continue; // no separator found

                const key = strings.trimSpaces(line[0..sep]);
                const value = strings.trimSpaces(line[sep + 1 ..]);
                if (key.len == 0) continue;

                try current_obj.putString(allocator, key, value);
            }
        }

        return root_expr;
    }
};

const std = @import("std");
const bun = @import("bun");
const strings = bun.strings;
const logger = bun.logger;

const js_ast = bun.ast;
const E = js_ast.E;
const Expr = js_ast.Expr;

