pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    var arena = bun.ArenaAllocator.init(globalThis.allocator());
    const allocator = arena.allocator();
    defer arena.deinit();

    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
    var ast_scope = ast_memory_allocator.enter(allocator);
    defer ast_scope.exit();

    var log = logger.Log.init(default_allocator);
    defer log.deinit();

    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const source = &logger.Source.initPathString("input.ini", input_slice.slice());
    const parse_result = ini.INI.parse(source, &log, allocator) catch |err| {
        if (err == error.StackOverflow) {
            return globalThis.throwStackOverflow();
        }
        return globalThis.throwValue(try log.toJS(globalThis, default_allocator, "Failed to parse INI"));
    };

    // Convert the Expr AST to a JSON string, then parse that JSON into a JS value.
    const buffer_writer = js_printer.BufferWriter.init(allocator);
    var writer = js_printer.BufferPrinter.init(buffer_writer);
    _ = js_printer.printJSON(
        *js_printer.BufferPrinter,
        &writer,
        parse_result,
        source,
        .{
            .mangled_props = null,
        },
    ) catch {
        return globalThis.throwValue(try log.toJS(globalThis, default_allocator, "Failed to print INI as JSON"));
    };

    const slice = writer.ctx.buffer.slice();
    var out = bun.String.borrowUTF8(slice);
    defer out.deref();

    return out.toJSByParseJSON(globalThis);
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callframe.argument(0);

    if (value.isUndefinedOrNull()) {
        return .js_undefined;
    }

    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("INI.stringify requires an object", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // First pass: emit global (no-section) key=value pairs.
    // These are top-level properties whose values are not plain objects.
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
            try .init(globalThis, try value.toObject(globalThis));
        defer iter.deinit();

        while (try iter.next()) |key_name| {
            const prop_val = iter.value;
            // Skip object values; they will be emitted as sections below.
            if (prop_val.isCell() and prop_val.isObject() and !prop_val.jsType().isArray()) continue;
            try appendKeyValue(&builder, globalThis, key_name, prop_val);
        }
    }

    // Second pass: emit section headers and their key=value pairs.
    // These are top-level properties whose values are plain (non-array) objects.
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
            try .init(globalThis, try value.toObject(globalThis));
        defer iter.deinit();

        while (try iter.next()) |key_name| {
            const prop_val = iter.value;
            if (!prop_val.isCell() or !prop_val.isObject() or prop_val.jsType().isArray()) continue;

            // Write section header.
            builder.append(.lchar, '[');
            builder.append(.string, key_name);
            builder.append(.latin1, "]\n");

            // Write nested key=value pairs.
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
                try .init(globalThis, try prop_val.toObject(globalThis));
            defer section_iter.deinit();

            while (try section_iter.next()) |inner_key| {
                try appendKeyValue(&builder, globalThis, inner_key, section_iter.value);
            }
        }
    }

    return builder.toString(globalThis);
}

/// Appends a single `key=value\n` line to `builder`.
/// Skips values that cannot be represented as INI scalars
/// (undefined, null, symbols, functions, objects).
fn appendKeyValue(
    builder: *wtf.StringBuilder,
    globalThis: *jsc.JSGlobalObject,
    key: bun.String,
    value: jsc.JSValue,
) bun.JSError!void {
    if (value.isUndefinedOrNull() or value.isSymbol() or value.isFunction()) return;
    // Objects/arrays are handled as sections in the caller; skip here.
    if (value.isCell() and value.isObject()) return;

    builder.append(.string, key);
    builder.append(.lchar, '=');

    if (value.isBoolean()) {
        builder.append(.latin1, if (value.asBoolean()) "true" else "false");
    } else if (value.isInt32()) {
        builder.append(.int, value.asInt32());
    } else if (value.isNumber()) {
        builder.append(.double, value.asNumber());
    } else if (value.isString()) {
        const str = try value.toBunString(globalThis);
        defer str.deref();
        builder.append(.string, str);
    }
    // BigInt and any other exotic type: skip the line entirely.
    else {
        // Remove the key= we already wrote by not appending the newline and
        // resetting through an early return isn't possible without a len-save.
        // Instead just append an empty value, which is valid INI.
    }

    builder.append(.lchar, '\n');
}

