import { INI } from "bun";
import { describe, expect, test } from "bun:test";

describe("Bun.INI.parse", () => {
  test("parses empty string to empty object", () => {
    expect(INI.parse("")).toEqual({});
  });

  test("parses global key=value pair", () => {
    expect(INI.parse("key=value")).toEqual({ key: "value" });
  });

  test("parses global key: value pair (colon separator)", () => {
    expect(INI.parse("key: value")).toEqual({ key: "value" });
  });

  test("parses multiple global key=value pairs", () => {
    expect(INI.parse("foo=bar\nbaz=qux")).toEqual({ foo: "bar", baz: "qux" });
  });

  test("trims whitespace from keys and values", () => {
    expect(INI.parse("  key  =  value  ")).toEqual({ key: "value" });
  });

  test("parses a section as a nested object", () => {
    expect(INI.parse("[section]\nkey=value")).toEqual({ section: { key: "value" } });
  });

  test("parses multiple sections", () => {
    const result = INI.parse("[a]\nx=1\n[b]\ny=2");
    expect(result).toEqual({ a: { x: "1" }, b: { y: "2" } });
  });

  test("parses global keys before and after sections", () => {
    const result = INI.parse("global=yes\n[section]\nkey=value");
    expect(result).toEqual({ global: "yes", section: { key: "value" } });
  });

  test("skips semicolon comment lines", () => {
    expect(INI.parse("; this is a comment\nkey=value")).toEqual({ key: "value" });
  });

  test("skips hash comment lines", () => {
    expect(INI.parse("# this is a comment\nkey=value")).toEqual({ key: "value" });
  });

  test("skips comment lines inside sections", () => {
    expect(INI.parse("[section]\n; comment\nkey=value")).toEqual({ section: { key: "value" } });
  });

  test("parses blank lines without error", () => {
    expect(INI.parse("\n\nkey=value\n\n")).toEqual({ key: "value" });
  });

  test("handles Windows-style CRLF line endings", () => {
    expect(INI.parse("key=value\r\n[section]\r\nfoo=bar\r\n")).toEqual({
      key: "value",
      section: { foo: "bar" },
    });
  });

  test("trims whitespace around section name", () => {
    expect(INI.parse("[  section  ]\nkey=value")).toEqual({ section: { key: "value" } });
  });

  test("allows empty value", () => {
    expect(INI.parse("key=")).toEqual({ key: "" });
  });

  test("merges duplicate section headers", () => {
    const result = INI.parse("[section]\nkey1=val1\n[section]\nkey2=val2");
    // Both keys should be present under the same section object.
    expect(result).toEqual({ section: { key1: "val1", key2: "val2" } });
  });

  test("throws on null input", () => {
    expect(() => INI.parse(null as any)).toThrow();
  });

  test("throws on undefined input", () => {
    expect(() => INI.parse(undefined as any)).toThrow();
  });

  test("parses a realistic config file", () => {
    const src = `
; database config
[database]
host = localhost
port = 5432
name = mydb

[server]
# bind address
host = 0.0.0.0
port = 8080
debug = false
`;
    expect(INI.parse(src)).toEqual({
      database: { host: "localhost", port: "5432", name: "mydb" },
      server: { host: "0.0.0.0", port: "8080", debug: "false" },
    });
  });
});

describe("Bun.INI.stringify", () => {
  test("stringifies an empty object to empty string", () => {
    expect(INI.stringify({})).toBe("");
  });

  test("stringifies a global key=value pair", () => {
    expect(INI.stringify({ key: "value" })).toBe("key=value\n");
  });

  test("stringifies multiple global key=value pairs", () => {
    // Property order is preserved.
    const result = INI.stringify({ foo: "bar", baz: "qux" });
    expect(result).toBe("foo=bar\nbaz=qux\n");
  });

  test("stringifies a section", () => {
    expect(INI.stringify({ section: { key: "value" } })).toBe("[section]\nkey=value\n");
  });

  test("global keys appear before sections", () => {
    const result = INI.stringify({ global: "yes", section: { key: "value" } });
    expect(result).toBe("global=yes\n[section]\nkey=value\n");
  });

  test("stringifies number values", () => {
    expect(INI.stringify({ port: 8080 })).toBe("port=8080\n");
  });

  test("stringifies boolean values", () => {
    expect(INI.stringify({ debug: true, verbose: false })).toBe("debug=true\nverbose=false\n");
  });

  test("stringifies number values inside sections", () => {
    expect(INI.stringify({ db: { port: 5432 } })).toBe("[db]\nport=5432\n");
  });

  test("skips undefined values", () => {
    expect(INI.stringify({ key: undefined as any, other: "val" })).toBe("other=val\n");
  });

  test("skips null values", () => {
    expect(INI.stringify({ key: null as any, other: "val" })).toBe("other=val\n");
  });

  test("returns undefined for undefined input", () => {
    expect(INI.stringify(undefined as any)).toBeUndefined();
  });

  test("throws for non-object input", () => {
    expect(() => INI.stringify("string" as any)).toThrow();
    expect(() => INI.stringify(42 as any)).toThrow();
  });

  test("round-trips a simple config", () => {
    const original = {
      debug: "true",
      database: { host: "localhost", port: "5432" },
    };
    const serialized = INI.stringify(original);
    const parsed = INI.parse(serialized);
    expect(parsed).toEqual(original);
  });
});

